<template><div><h1>家庭户历史归档</h1><el-card shadow="never"><el-table :data="rows" v-loading="loading" border><el-table-column prop="householdNoSnapshot" label="户号"/><el-table-column prop="headPersonNameSnapshot" label="原户主"/><el-table-column prop="registeredAddressSnapshot" label="历史地址"/><el-table-column prop="regionCodeSnapshot" label="区划"/><el-table-column prop="cancellationReasonCode" label="销户原因"/><el-table-column prop="archivedAt" label="归档时间"/></el-table></el-card></div></template><script setup>import{onMounted,ref}from'vue';import{listHouseholdArchives}from'../../api/cancellations';const rows=ref([]),loading=ref(false);async function load(){loading.value=true;try{rows.value=(await listHouseholdArchives({size:50})).content||[]}finally{loading.value=false}}onMounted(load);</script>
